// Extract completed subtask info
const body = $json.body || $json;
const issue = body.issue || {};
const fields = issue.fields || {};

const completedKey = issue.key;
const parentKey = fields.parent?.key || null;

if (!completedKey || !parentKey) {
  return [{ json: { skip: true, reason: 'Missing issue key or parent' } }];
}

return [{
  json: {
    completedKey,
    parentKey,
    summary: fields.summary || '',
    status: fields.status?.name || 'Done'
  }
}];

// Find issues that were blocked by the completed subtask
const issueLinks = $json.fields?.issuelinks || [];
const completedInfo = $('Extract completed info').first().json;
const completedKey = completedInfo.completedKey;
const parentKey = completedInfo.parentKey;

// Find "blocks" links - issues that this subtask was blocking
const blockedIssues = [];
for (const link of issueLinks) {
  const linkType = link.type?.name?.toLowerCase() || '';
  if (linkType.includes('block')) {
    // outwardIssue = issue that THIS issue blocks
    const blockedIssue = link.outwardIssue;
    if (blockedIssue) {
      blockedIssues.push({
        key: blockedIssue.key,
        status: blockedIssue.fields?.status?.name || '',
        summary: blockedIssue.fields?.summary || ''
      });
    }
  }
}

if (blockedIssues.length === 0) {
  return [{ json: { skip: true, reason: 'No blocked issues found', completedKey, parentKey } }];
}

return [{
  json: {
    completedKey,
    parentKey,
    blockedIssues,
    count: blockedIssues.length
  }
}];

// Split blocked issues for individual processing
const blockedIssues = $json.blockedIssues || [];
const parentKey = $json.parentKey;
const completedKey = $json.completedKey;

return blockedIssues.map(issue => ({
  json: {
    issueKey: issue.key,
    status: issue.status,
    summary: issue.summary,
    parentKey,
    completedKey
  }
}));

// Check if this blocked issue is now fully unblocked
const issue = $json;
const issueLinks = issue.fields?.issuelinks || [];
const labels = issue.fields?.labels || [];
const prevData = $('Split blocked issues').first().json;

// Find remaining blockers (issues that block this one and are NOT done)
const remainingBlockers = [];
for (const link of issueLinks) {
  const linkType = link.type?.name?.toLowerCase() || '';
  if (linkType.includes('block')) {
    // inwardIssue = issue that blocks THIS issue
    const blockerIssue = link.inwardIssue;
    if (blockerIssue) {
      const blockerStatus = blockerIssue.fields?.status?.name?.toLowerCase() || '';
      const isDone = blockerStatus === 'done' || blockerStatus === 'closed' || blockerStatus === 'resolved';
      if (!isDone) {
        remainingBlockers.push(blockerIssue.key);
      }
    }
  }
}

const isFullyUnblocked = remainingBlockers.length === 0;

// Extract agent label
const agentLabel = labels.find(l => l.startsWith('agent:'));

// Agent label mapping
const agentLabelMap = {
  'agent:planner': 'engineer-planner',
  'agent:implementer': 'engineer-implementer',
  'agent:reviewer': 'engineer-reviewer',
  'agent:pm': 'product-manager',
  'agent:ui': 'ui-engineer',
  'agent:marketing': 'marketing',
  'agent:creative-assets': 'creative-assets',
  'agent:bug-triage': 'bug-triage',
  'agent:security': 'security-agent',
  'agent:sprint-report': 'sprint-reporter',
  'agent:standup': 'sprint-reporter'
};

const agent = agentLabel ? (agentLabelMap[agentLabel] || 'engineer-implementer') : null;

// Check current status - only trigger if not already in progress or done
const currentStatus = issue.fields?.status?.name?.toLowerCase() || '';
const shouldTrigger = isFullyUnblocked && 
                      agentLabel && 
                      currentStatus !== 'done' && 
                      currentStatus !== 'in progress';

return [{
  json: {
    issueKey: issue.key,
    isFullyUnblocked,
    remainingBlockers,
    agentLabel,
    agent,
    shouldTrigger,
    currentStatus,
    summary: issue.fields?.summary || '',
    description: issue.fields?.description?.content?.[0]?.content?.[0]?.text || '',
    parentKey: issue.fields?.parent?.key || prevData.parentKey
  }
}];

// Log that subtask still has blockers
const blockers = $json.remainingBlockers || [];
console.log(`Subtask ${$json.issueKey} still blocked by: ${blockers.join(', ')}`);

return [{
  json: {
    status: 'still-blocked',
    issueKey: $json.issueKey,
    remainingBlockers: blockers
  }
}];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
